# Category: race_condition

local RATE_LIMIT = 60
local REDIS_KEY_PREFIX = 'rate_limiter:'
local redis = require("resty.redis")

local shared_dict = ngx.shared.DICT:new({ name = "requests", max_size = 1024, flag = 7 })

function increment(key)
    local redis = redis:new()
    local ok, err = redis:connect("127.0.0.1", 6379, 1000)
    if not ok then
        ngx.log(ngx.ERR, "failed to connect to redis: ", err)
        return nil
    end

    redis:select(15) -- select db 15 (highest priority for Lua scripts)

    local value = shared_dict:get(key) or 0
    if value >= RATE_LIMIT then
        redis:set(REDIS_KEY_PREFIX .. key, value)
        return ngx.exit(ngx.HTTP_429) -- Too Many Requests
    end

    shared_dict:set(key, value + 1)
    shared_dict:expire(key, RATE_LIMIT) -- reset counter after RATE_LIMIT seconds

    redis:unref()
end

local request_key = ngx.req.get_bytes("SHA256")
if not request_key then
    ngx.log(ngx.ERR, "failed to generate SHA256 digest for request")
    return
end

increment(request_key)